const b=$input.first().json;
if(b.action==='resolver'){
  return [{json:{_skip:true}},{json:b}];
}
// For 'abrir' - ensure valid enum values
return [{json:{
  autor_id: b.autor_id||null,
  assunto: b.assunto||'Suporte',
  descricao: b.descricao||'',
  prioridade: ['baixa','media','alta','critica'].indexOf(b.prioridade)>=0 ? b.prioridade : 'media',
  status: 'aberto'
}},{json:{_skip:true}}];
